        |> put_private(:session_data, session_data)
        |> register_before_send(&save_session/1)
      
      {:error, _reason} ->
        conn
        |> put_private(:session_data, %{})
        |> register_before_send(&save_session/1)
    end
  end

  def get_session(conn, key) do
    session_data = conn.private[:session_data] || %{}
    Map.get(session_data, key)
  end

  def put_session(conn, key, value) do
    session_data = conn.private[:session_data] || %{}
    updated_session = Map.put(session_data, key, value)
    put_private(conn, :session_data, updated_session)
  end

  def delete_session(conn, key) do
    session_data = conn.private[:session_data] || %{}
    updated_session = Map.delete(session_data, key)
    put_private(conn, :session_data, updated_session)
  end

