    if map_size(session_data) > 0 do
      encrypted_session = SessionManager.create_session(session_data, max_age: @max_age)
      
      put_resp_cookie(conn, @session_key, encrypted_session,
        max_age: @max_age,
        http_only: true,
        secure: true,
        same_site: "Lax"
      )
    else
